import React, { memo } from "react";
import COLORS from "../../constants/colors";

// 提取样式常量，提升可维护性
const CONTAINER_STYLE = {
  background: COLORS.white,
  borderRadius: "18px",
  padding: "1rem",
  marginBottom: "1rem",
  border: `1px solid ${COLORS.line}`,
};

const TITLE_STYLE = {
  fontWeight: 700,
  color: COLORS.text,
  marginBottom: "0.25rem",
};

const SUBTITLE_STYLE = {
  color: COLORS.subtext,
  fontSize: "0.92rem",
  marginBottom: "0.9rem",
};

const GRID_STYLE = {
  display: "grid",
  gridTemplateColumns: "repeat(2, minmax(0, 1fr))",
  gap: "0.75rem",
};

const BUTTON_BASE_STYLE = {
  borderRadius: "14px",
  padding: 0,
  overflow: "hidden",
  cursor: "pointer",
  textAlign: "left",
  boxSizing: "border-box",
  transition: "all 0.2s ease",
  border: `1px solid ${COLORS.line}`,
};

const IMAGE_CONTAINER_STYLE = {
  height: "74px",
  backgroundSize: "cover",
  backgroundPosition: "center",
  backgroundRepeat: "no-repeat",
  position: "relative",
};

const TAG_CONTAINER_STYLE = {
  position: "absolute",
  top: "8px",
  left: "8px",
  display: "flex",
  gap: "6px",
  flexWrap: "wrap",
};

const CURRENT_TAG_STYLE = {
  background: "rgba(255,255,255,0.92)",
  color: COLORS.primary,
  fontSize: "0.72rem",
  fontWeight: 700,
  borderRadius: "999px",
  padding: "0.15rem 0.45rem",
};

const SELECTED_TAG_STYLE = {
  background: COLORS.primary,
  color: "#fff",
  fontSize: "0.72rem",
  fontWeight: 700,
  borderRadius: "999px",
  padding: "0.15rem 0.45rem",
};

const CONTENT_CONTAINER_STYLE = {
  padding: "0.8rem",
};

const HEADER_ROW_STYLE = {
  display: "flex",
  alignItems: "center",
  justifyContent: "space-between",
  gap: "0.5rem",
  marginBottom: "0.4rem",
};

const LANDMARK_NAME_STYLE = {
  fontWeight: 700,
  color: COLORS.text,
  fontSize: "0.98rem",
  lineHeight: 1.3,
};

const STATUS_BADGE_STYLE = {
  flexShrink: 0,
  fontSize: "0.78rem",
  fontWeight: 700,
  borderRadius: "999px",
  padding: "0.18rem 0.5rem",
};

const DESC_STYLE = {
  color: COLORS.subtext,
  fontSize: "0.86rem",
  lineHeight: 1.5,
  minHeight: "2.6em",
};

const ACTION_TEXT_STYLE = {
  marginTop: "0.55rem",
  fontSize: "0.82rem",
  fontWeight: 700,
};

// 提取地标卡片组件，提升可读性
const LandmarkCard = ({
  landmark,
  unlocked,
  isCurrent,
  isSelected,
  resource,
  onLandmarkClick,
  onShowMessage,
}) => {
  const handleClick = () => {
    if (unlocked) {
      onLandmarkClick?.(landmark);
    } else {
      onShowMessage?.(
        `需要 ${landmark.need} 点能量才能解锁【${landmark.name}】`
      );
    }
  };

  // 动态计算按钮样式
  const buttonStyle = {
    ...BUTTON_BASE_STYLE,
    border: isSelected
      ? `2px solid ${COLORS.primary}`
      : `1px solid ${COLORS.line}`,
    background: unlocked ? "#fff" : "#FAF7F2",
    opacity: unlocked ? 1 : 0.9,
    boxShadow: isSelected
      ? "0 0 0 3px rgba(93, 56, 145, 0.10)"
      : "none",
  };

  // 动态计算图片样式
  const imageStyle = {
    ...IMAGE_CONTAINER_STYLE,
    backgroundImage: resource?.bgImage
      ? `linear-gradient(rgba(0,0,0,0.16), rgba(0,0,0,0.28)), url(${resource.bgImage})`
      : "linear-gradient(135deg, #EAEAEA, #DADADA)",
    filter: unlocked ? "none" : "grayscale(100%) brightness(0.85)",
  };

  // 动态计算状态徽章样式
  const statusBadgeStyle = {
    ...STATUS_BADGE_STYLE,
    color: unlocked ? "#1E9E57" : "#B26B00",
    background: unlocked ? "#EAF8F0" : "#FFF4E5",
  };

  // 动态计算操作文本样式
  const actionTextStyle = {
    ...ACTION_TEXT_STYLE,
    color: unlocked ? COLORS.primary : COLORS.subtext,
  };

  return (
    <button
      key={landmark.id}
      type="button"
      onClick={handleClick}
      style={buttonStyle}
      aria-label={unlocked ? `进入${landmark.name}` : `解锁${landmark.name}需要${landmark.need}点能量`}
    >
      <div style={imageStyle}>
        <div style={TAG_CONTAINER_STYLE}>
          {isCurrent && <span style={CURRENT_TAG_STYLE}>当前地标</span>}
          {isSelected && <span style={SELECTED_TAG_STYLE}>当前背景</span>}
        </div>
      </div>

      <div style={CONTENT_CONTAINER_STYLE}>
        <div style={HEADER_ROW_STYLE}>
          <div style={LANDMARK_NAME_STYLE}>{landmark.name}</div>
          <div style={statusBadgeStyle}>
            {unlocked ? "已解锁" : `需${landmark.need}★`}
          </div>
        </div>

        <div style={DESC_STYLE}>
          {landmark.desc ||
            (unlocked
              ? "点击进入地图，播放转场视频并切换背景"
              : "继续学习获取能量后解锁")}
        </div>

        <div style={actionTextStyle}>
          {unlocked ? "点击进入" : `解锁需要 ${landmark.need} 点能量`}
        </div>
      </div>
    </button>
  );
};

// 使用memo优化性能，避免不必要的重渲染
const LandmarkMapCard = memo(({
  landmarks = [],
  energy = 0,
  currentLandmark,
  onShowMessage,
  onLandmarkClick,
  selectedLandmarkId,
  getLandmarkResource,
}) => {
  const safeLandmarks = Array.isArray(landmarks) ? landmarks : [];

  return (
    <div style={CONTAINER_STYLE}>
      <div style={TITLE_STYLE}>巴黎地图</div>

      <div style={SUBTITLE_STYLE}>
        当前所在：{currentLandmark?.name || "未解锁"} ｜ 当前能量：{energy}
      </div>

      <div style={GRID_STYLE}>
        {safeLandmarks.map((landmark) => {
          const unlocked = Number(energy) >= Number(landmark?.need || 0);
          const isCurrent = String(currentLandmark?.id) === String(landmark?.id);
          const isSelected = String(selectedLandmarkId) === String(landmark?.id);
          const resource = getLandmarkResource?.(landmark);

          return (
            <LandmarkCard
              key={landmark.id}
              landmark={landmark}
              unlocked={unlocked}
              isCurrent={isCurrent}
              isSelected={isSelected}
              resource={resource}
              onLandmarkClick={onLandmarkClick}
              onShowMessage={onShowMessage}
            />
          );
        })}
      </div>
    </div>
  );
});

export default LandmarkMapCard;