import React, { useEffect, useMemo, useState, useRef, useCallback } from "react";
import Particles from "react-tsparticles";
import { loadFull } from "tsparticles";

import { mainCardStyle, pageStyle, primaryBtnStyle } from "../../styles/commonStyles";
import HomeTopSection from "./HomeTopSection";
import LandmarkMapCard from "./LandmarkMapCard";
import CheckInCard from "./CheckInCard";
import HomeActionPanel from "./HomeActionPanel";
import HomeBottomNav from "./HomeBottomNav";
import LandmarkUnlockModal from "./LandmarkUnlockModal";
import InfoMessage from "../common/InfoMessage";
import COLORS from "../../constants/colors";
import {
  DEFAULT_BG_IMAGE,
  getLandmarkResource,
} from "../../constants/landmarkResources";
// 导入词库
import { APP_WORDS_SOURCE } from "../../data/words";

const BG_STORAGE_KEY = "homepage_selected_landmark_bg_id";

// 核心：通用悬浮放大样式（适配图标/按钮）
const hoverScaleStyle = {
  transition: "transform 0.2s ease, box-shadow 0.2s ease",
  transform: "scale(1)",
  cursor: "pointer",
};

// 图标专用悬浮样式（放大比例更大）
const iconHoverStyle = {
  ...hoverScaleStyle,
  transform: "scale(1)",
  transition: "transform 0.15s ease-in-out, box-shadow 0.15s ease-in-out",
};

// 搜索结果卡片样式
const searchResultCardStyle = {
  background: COLORS.white,
  borderRadius: "12px",
  padding: "1rem",
  margin: "0.5rem 0",
  border: `1px solid ${COLORS.line}`,
  boxShadow: "0 2px 8px rgba(0,0,0,0.08)",
  maxHeight: "300px",
  overflowY: "auto",
};

// 单个单词项样式
const wordItemStyle = {
  padding: "0.8rem 0",
  borderBottom: `1px solid ${COLORS.line}`,
  cursor: "pointer",
  "&:last-child": {
    borderBottom: "none",
  },
  transition: "background-color 0.2s ease",
};

export default function HomePage({
  state,
  currentLandmark,
  landmarks,
  message,
  onShowMessage,
  onCheckIn,
  onStartLearn,
  onStartReview,
  onGoMyContent,
  onGoStatistics,
  onCloseLandmarkUnlock,
  onDailyPlanChange,
  // 新增：跳转详情页回调（需在父组件实现路由/页面切换逻辑）
  onGoWordDetail = () => {},
}) {
  const particlesInit = useCallback(async (main) => {
    await loadFull(main);
  }, []);

  const particlesOptions = useMemo(
    () => ({
      fullScreen: { enable: false },
      background: {
        color: { value: "transparent" },
      },
      fpsLimit: 60,
      interactivity: {
        events: {
          onClick: { enable: true, mode: "push" },
          onHover: { enable: true, mode: "grab" },
          resize: true,
        },
        modes: {
          push: { quantity: 3 },
          grab: { distance: 150 },
        },
      },
      particles: {
        color: { value: "#1976d2" },
        links: {
          color: "#1976d2",
          distance: 150,
          enable: true,
          opacity: 0.32,
          width: 1,
        },
        move: {
          direction: "none",
          enable: true,
          outModes: { default: "bounce" },
          speed: 2,
        },
        number: {
          density: { enable: true, area: 800 },
          value: 40,
        },
        opacity: { value: 0.5 },
        shape: { type: "circle" },
        size: { value: { min: 1, max: 3 } },
      },
      detectRetina: true,
    }),
    []
  );

  // 原有状态
  const [selectedLandmarkId, setSelectedLandmarkId] = useState(() => {
    try {
      return (
        window.localStorage.getItem(BG_STORAGE_KEY) ||
        currentLandmark?.id ||
        landmarks?.[0]?.id ||
        1
      );
    } catch {
      return currentLandmark?.id || landmarks?.[0]?.id || 1;
    }
  });
  const [activeBgImage, setActiveBgImage] = useState(DEFAULT_BG_IMAGE);
  const [pendingVideoLandmark, setPendingVideoLandmark] = useState(null);
  const [videoError, setVideoError] = useState(false);
  const videoRef = useRef(null);
  const [preloadedVideo, setPreloadedVideo] = useState(null);

  // 新增：搜索相关状态
  const [searchInput, setSearchInput] = useState("");
  const [searchResults, setSearchResults] = useState([]);
  const [showSearchResults, setShowSearchResults] = useState(false);

  const energy = Number(state?.user?.energy || 0);

  const selectedLandmark = useMemo(() => {
    return (
      landmarks?.find((item) => String(item.id) === String(selectedLandmarkId)) ||
      currentLandmark ||
      landmarks?.[0] ||
      null
    );
  }, [landmarks, selectedLandmarkId, currentLandmark]);

  // 原有副作用
  useEffect(() => {
    const res = getLandmarkResource(selectedLandmark);
    if (res?.video) {
      setPreloadedVideo(res.video);
    }
  }, [selectedLandmark]);

  useEffect(() => {
    const resource = getLandmarkResource(selectedLandmark);
    setActiveBgImage(resource?.bgImage || DEFAULT_BG_IMAGE);
  }, [selectedLandmark]);

  useEffect(() => {
    try {
      const saved = window.localStorage.getItem(BG_STORAGE_KEY);
      if (!saved && currentLandmark?.id) {
        setSelectedLandmarkId(currentLandmark.id);
      }
    } catch {
      if (currentLandmark?.id) {
        setSelectedLandmarkId(currentLandmark.id);
      }
    }
  }, [currentLandmark]);

  // 优化：单词搜索逻辑（强化汉语匹配，支持多维度检索）
  useEffect(() => {
    if (!searchInput.trim()) {
      setSearchResults([]);
      setShowSearchResults(false);
      return;
    }

    const lowerInput = searchInput.toLowerCase().trim();
    // 模糊匹配：支持法语（word/phonetic）或汉语（translation/commonMeanings/用法）
    const matchedWords = APP_WORDS_SOURCE.filter(word => {
      // 匹配法语单词/音标
      const matchFrench = 
        word.word.toLowerCase().includes(lowerInput) ||
        (word.phonetic && word.phonetic.toLowerCase().includes(lowerInput));
      
      // 匹配汉语翻译/常见释义
      const matchChineseBase = 
        word.translation.toLowerCase().includes(lowerInput) ||
        word.commonMeanings.some(meaning => meaning.toLowerCase().includes(lowerInput));
      
      // 匹配用法中的汉语（增强汉语检索覆盖）
      const matchChineseUsage = word.usages?.some(usage => 
        usage.title.toLowerCase().includes(lowerInput) ||
        usage.meaning.toLowerCase().includes(lowerInput) ||
        usage.translation.toLowerCase().includes(lowerInput)
      );

      // 匹配派生词中的汉语
      const matchChineseDerivative = word.derivatives?.some(deriv => 
        deriv.meaning.toLowerCase().includes(lowerInput) ||
        deriv.usage.toLowerCase().includes(lowerInput)
      );

      return matchFrench || matchChineseBase || matchChineseUsage || matchChineseDerivative;
    });

    setSearchResults(matchedWords);
    setShowSearchResults(matchedWords.length > 0);
  }, [searchInput]);

  // 新增：点击单词项进入详情页
  const handleWordItemClick = (word) => {
    if (!word) return;
    // 清空搜索状态
    clearSearchInput();
    // 跳转详情页（父组件需实现具体跳转逻辑，如路由push/显示详情组件）
    onGoWordDetail(word);
    // 可选：提示信息
    onShowMessage?.(`查看单词：${word.word} - ${word.translation}`);
  };

  const applyLandmarkBackground = (landmark) => {
    if (!landmark) return;
    setSelectedLandmarkId(landmark.id);
    try {
      window.localStorage.setItem(BG_STORAGE_KEY, String(landmark.id));
    } catch {}
    onShowMessage?.(`已进入【${landmark.name}】地图`);
  };

  const handleLandmarkClick = (landmark) => {
    if (!landmark) return;

    const unlocked = energy >= Number(landmark?.need || 0);
    if (!unlocked) {
      onShowMessage?.(`需要 ${landmark.need} 点能量才能解锁【${landmark.name}】`);
      return;
    }

    const resource = getLandmarkResource(landmark);

    if (resource?.video) {
      setVideoError(false);
      setPendingVideoLandmark(landmark);
      return;
    }

    applyLandmarkBackground(landmark);
  };

  const finishLandmarkTransition = () => {
    if (!pendingVideoLandmark) return;
    applyLandmarkBackground(pendingVideoLandmark);
    setPendingVideoLandmark(null);
  };

  const handleUnlockEnter = () => {
    if (!state?.ui?.showLandmarkUnlock) return;
    onCloseLandmarkUnlock?.();
    handleLandmarkClick(state.ui.showLandmarkUnlock);
  };

  // 新增：清空搜索输入
  const clearSearchInput = () => {
    setSearchInput("");
    setSearchResults([]);
    setShowSearchResults(false);
  };

  return (
    <div
      style={{
        ...pageStyle(),
        backgroundImage: `linear-gradient(rgba(235,235,235,0.62), rgba(235,235,235,0.72)), url(${activeBgImage || DEFAULT_BG_IMAGE})`,
        backgroundSize: "cover",
        backgroundPosition: "center",
        backgroundRepeat: "no-repeat",
        transition: "background-image 0.35s ease",
        position: "relative",
        minHeight: "100vh",
        overflow: "hidden",
      }}
    >
      {/* 背景增强层 */}
      <div
        style={{
          position: "absolute",
          inset: 0,
          background:
            "linear-gradient(rgba(60,72,92,0.18), rgba(88,64,110,0.14))",
          zIndex: 0,
        }}
      />

      {/* 粒子层 */}
      <Particles
        id="tsparticles"
        init={particlesInit}
        options={particlesOptions}
        style={{
          position: "absolute",
          inset: 0,
          width: "100%",
          height: "100%",
          zIndex: 1,
        }}
      />

      {/* 页面内容层 */}
      <div style={{ position: "relative", zIndex: 2 }}>
        <div style={mainCardStyle()}>
          {/* 顶部区域 */}
          <HomeTopSection
            dateText={state.app.currentDateText}
            weekdayText={state.app.currentWeekdayText}
            weather={state.app.weather}
            iconClassName="hover-scale-icon"
          />

          {/* 新增：单词搜索组件 */}
          <div 
            style={{
              background: COLORS.white,
              borderRadius: "18px",
              padding: "1rem",
              marginBottom: "1rem",
              border: `1px solid ${COLORS.line}`,
              position: "relative",
            }}
          >
            <div style={{ fontWeight: 700, color: COLORS.text, marginBottom: "0.8rem" }}>
              单词检索
            </div>
            {/* 搜索输入框 + 放大镜 */}
            <div style={{ position: "relative" }}>
              <input
                type="text"
                placeholder="输入法语/汉语检索单词（如：aboutir / 导致）"
                value={searchInput}
                onChange={(e) => setSearchInput(e.target.value)}
                style={{
                  width: "100%",
                  border: `1px solid ${COLORS.line}`,
                  borderRadius: "12px",
                  padding: "0.8rem 2.5rem 0.8rem 1rem",
                  fontSize: "1rem",
                  outline: "none",
                  boxSizing: "border-box",
                }}
              />
              {/* 放大镜图标 */}
              <svg
                xmlns="http://www.w3.org/2000/svg"
                width="20"
                height="20"
                fill="currentColor"
                className="bi bi-search"
                viewBox="0 0 16 16"
                style={{
                  position: "absolute",
                  right: "1rem",
                  top: "50%",
                  transform: "translateY(-50%)",
                  color: COLORS.subtext,
                  pointerEvents: "none",
                }}
              >
                <path d="M11.742 10.344a6.5 6.5 0 1 0-1.397 1.398h-.001c.03.04.062.078.098.115l3.85 3.85a1 1 0 0 0 1.415-1.414l-3.85-3.85a1.007 1.007 0 0 0-.115-.1zM12 6.5a5.5 5.5 0 1 1-11 0 5.5 5.5 0 0 1 11 0z" />
              </svg>
              {/* 清空按钮 */}
              {searchInput && (
                <button
                  onClick={clearSearchInput}
                  style={{
                    position: "absolute",
                    right: "2.8rem",
                    top: "50%",
                    transform: "translateY(-50%)",
                    background: "transparent",
                    border: "none",
                    color: COLORS.subtext,
                    cursor: "pointer",
                    fontSize: "1.2rem",
                    padding: "0 0.3rem",
                  }}
                >
                  ×
                </button>
              )}
            </div>

            {/* 搜索结果展示 */}
            {showSearchResults && (
              <div style={searchResultCardStyle}>
                {searchResults.map((word) => (
                  <div 
                    key={word.id} 
                    style={{
                      ...wordItemStyle,
                      // 新增：hover 背景高亮
                      ":hover": {
                        backgroundColor: COLORS.soft,
                      },
                    }}
                    // 新增：点击进入详情页
                    onClick={() => handleWordItemClick(word)}
                  >
                    <div style={{ display: "flex", justifyContent: "space-between", marginBottom: "0.4rem" }}>
                      <span style={{ fontSize: "1.1rem", fontWeight: 700, color: COLORS.text }}>
                        {word.word}
                      </span>
                      <span style={{ color: COLORS.subtext, fontSize: "0.9rem" }}>
                        {word.phonetic}
                      </span>
                    </div>
                    <div style={{ color: COLORS.text, marginBottom: "0.3rem" }}>
                      <span style={{ fontWeight: 500 }}>{word.type}</span> · {word.translation}
                    </div>
                    {word.example && (
                      <div style={{ fontSize: "0.9rem", color: COLORS.subtext, marginTop: "0.3rem" }}>
                        <span style={{ fontStyle: "italic" }}>{word.example}</span>
                        {word.exampleTranslation && (
                          <span style={{ marginLeft: "0.5rem" }}>· {word.exampleTranslation}</span>
                        )}
                      </div>
                    )}
                    {word.derivatives && word.derivatives.length > 0 && (
                      <div style={{ fontSize: "0.9rem", marginTop: "0.3rem" }}>
                        <span style={{ color: COLORS.subtext }}>衍生词：</span>
                        {word.derivatives.map((deriv, idx) => (
                          <span key={idx} style={{ marginLeft: idx > 0 ? "0.5rem" : 0 }}>
                            {deriv.word} ({deriv.type})：{deriv.meaning}
                          </span>
                        ))}
                      </div>
                    )}
                  </div>
                ))}
              </div>
            )}
            {!showSearchResults && searchInput && (
              <div style={{ textAlign: "center", padding: "1rem", color: COLORS.subtext }}>
                未找到匹配的单词
              </div>
            )}
          </div>

          {/* 地标卡片 */}
          <LandmarkMapCard
            landmarks={landmarks}
            energy={state.user.energy}
            currentLandmark={currentLandmark}
            onShowMessage={onShowMessage}
            onLandmarkClick={handleLandmarkClick}
            selectedLandmarkId={selectedLandmarkId}
            getLandmarkResource={getLandmarkResource}
            landmarkIconStyle={iconHoverStyle}
          />

          {/* 每日背词计划 */}
          <div
            style={{
              background: COLORS.white,
              borderRadius: "18px",
              padding: "1rem",
              marginBottom: "1rem",
              border: `1px solid ${COLORS.line}`,
            }}
          >
            <div style={{ fontWeight: 700, color: COLORS.text }}>每日背词计划</div>
            <div
              style={{
                color: COLORS.subtext,
                fontSize: "0.92rem",
                marginTop: "0.25rem",
                marginBottom: "0.9rem",
              }}
            >
              默认 10 个单词，可自行调整
            </div>

            <div style={{ display: "flex", flexDirection: "column", gap: "0.75rem" }}>
              <input
                type="number"
                min="1"
                max="100"
                value={state.user.dailyPlanCount}
                onChange={(e) => onDailyPlanChange(e.target.value)}
                style={{
                  width: "100%",
                  border: `1px solid ${COLORS.line}`,
                  borderRadius: "12px",
                  padding: "0.8rem",
                  fontSize: "1rem",
                  outline: "none",
                  boxSizing: "border-box",
                }}
              />

              <button
                onClick={() => onDailyPlanChange(10)}
                className="hover-scale-btn"
                style={{
                  ...primaryBtnStyle(),
                  ...hoverScaleStyle,
                  width: "100%",
                  padding: "0.8rem 1rem",
                  boxSizing: "border-box",
                  border: "none",
                  borderRadius: "12px",
                  cursor: "pointer",
                  fontSize: "1rem",
                }}
              >
                恢复默认
              </button>
            </div>
          </div>

          {/* 签到卡片 */}
          <CheckInCard
            streak={state.user.streak}
            showCheckinText={state.ui.showCheckinText}
            onCheckIn={onCheckIn}
            checkinBtnStyle={hoverScaleStyle}
          />

          <InfoMessage message={message} />

          {/* 操作面板 */}
          <HomeActionPanel
            onStartLearn={onStartLearn}
            onStartReview={onStartReview}
            btnStyle={hoverScaleStyle}
          />

          {/* 底部导航 */}
          <HomeBottomNav
            currentScreen={state.ui.screen}
            onGoMyContent={onGoMyContent}
            onGoStatistics={onGoStatistics}
            navIconStyle={iconHoverStyle}
          />
        </div>

        {/* 地标解锁弹窗 */}
        <LandmarkUnlockModal
          landmark={state.ui.showLandmarkUnlock}
          onClose={onCloseLandmarkUnlock}
          onEnter={handleUnlockEnter}
          getLandmarkResource={getLandmarkResource}
          modalBtnStyle={hoverScaleStyle}
        />

        {/* 视频过渡弹窗 */}
        {pendingVideoLandmark && (
          <div
            style={{
              position: "fixed",
              inset: 0,
              background: "rgba(0,0,0,0.82)",
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
              zIndex: 1001,
              padding: "1rem",
            }}
          >
            <div
              style={{
                width: "100%",
                maxWidth: "760px",
                borderRadius: "18px",
                overflow: "hidden",
                background: "#111",
                boxShadow: "0 18px 50px rgba(0,0,0,0.35)",
              }}
            >
              {!videoError ? (
                <>
                  <video
                    ref={videoRef}
                    src={preloadedVideo || getLandmarkResource(pendingVideoLandmark).video}
                    poster={getLandmarkResource(pendingVideoLandmark).videoPoster}
                    autoPlay
                    playsInline
                    controls
                    preload="auto"
                    onEnded={finishLandmarkTransition}
                    onError={() => setVideoError(true)}
                    style={{
                      width: "100%",
                      display: "block",
                      maxHeight: "72vh",
                      background: "#000",
                    }}
                  />
                  <div
                    style={{
                      display: "flex",
                      justifyContent: "flex-end",
                      gap: "0.75rem",
                      padding: "0.9rem",
                      background: "#111",
                    }}
                  >
                    <button
                      onClick={() => setPendingVideoLandmark(null)}
                      className="hover-scale-btn"
                      style={{
                        ...hoverScaleStyle,
                        background: "transparent",
                        color: "#fff",
                        border: "1px solid rgba(255,255,255,0.25)",
                        borderRadius: "10px",
                        padding: "0.72rem 1rem",
                        cursor: "pointer",
                      }}
                    >
                      关闭
                    </button>
                    <button
                      onClick={finishLandmarkTransition}
                      className="hover-scale-btn"
                      style={{
                        ...primaryBtnStyle(),
                        ...hoverScaleStyle,
                        border: "none",
                        borderRadius: "10px",
                        padding: "0.72rem 1rem",
                        cursor: "pointer",
                      }}
                    >
                      跳过并进入
                    </button>
                  </div>
                </>
              ) : (
                <div
                  style={{
                    minHeight: "260px",
                    display: "flex",
                    flexDirection: "column",
                    alignItems: "center",
                    justifyContent: "center",
                    padding: "2rem",
                    color: "#fff",
                    textAlign: "center",
                    gap: "1rem",
                  }}
                >
                  <div style={{ fontSize: "1.05rem", fontWeight: 700 }}>
                    视频加载失败，仍可直接进入地图
                  </div>
                  <button
                    onClick={finishLandmarkTransition}
                    className="hover-scale-btn"
                    style={{
                      ...primaryBtnStyle(),
                      ...hoverScaleStyle,
                      border: "none",
                      borderRadius: "10px",
                      padding: "0.8rem 1rem",
                      cursor: "pointer",
                    }}
                  >
                    直接进入
                  </button>
                </div>
              )}
            </div>
          </div>
        )}
      </div>
    </div>
  );
}