import React, { useState, useEffect } from "react";
import COLORS from "../../constants/colors";
import HeartView from "../common/HeartView";
import FlowTopBar from "../common/FlowTopBar";
import {
  detailPanelStyle,
  detailTagStyle,
  heroWordStyle,
  mainCardStyle,
  miniBtnStyle,
  pageStyle,
} from "../../styles/commonStyles";
import { speakFrench } from "../../utils/speech";
import OpenAI from "openai";

export default function WordDetailPage({
  word,
  heartCount = 0,
  detailTab,
  tempNote,
  meaningExampleIndex,
  onSetDetailTab,
  onSetTempNote,
  onSetMeaningExampleIndex,
  onSaveNote,
  onNext,
  onMarkWrong,
  onPrev,
  onStar,
  onSkip,
  onHome,
  disablePrev = false,
}) {
  const [imageUrl, setImageUrl] = useState(null);

  useEffect(() => {
    if (!word) return;

    async function fetchImage() {
      try {
        const openai = new OpenAI({
          apiKey: process.env.REACT_APP_OPENAI_API_KEY,
        });

        const prompt = `A high-quality, realistic illustration of the word "${word.word}" (${word.translation})`;

        const response = await openai.images.generate({
          model: "gpt-image-1",
          prompt,
          size: "1024x1024",
        });

        if (response.data?.[0]?.url) {
          setImageUrl(response.data[0].url);
        } else {
          setImageUrl("https://picsum.photos/800/600");
        }
      } catch (err) {
        console.error("Image generation failed:", err);
        setImageUrl("https://picsum.photos/800/600");
      }
    }

    fetchImage();
  }, [word]);

  if (!word) return null;

  const meanings = word.commonMeanings || [];

  return (
    <div style={pageStyle()}>
      <div style={mainCardStyle()}>
        <FlowTopBar
          title="法语单词界面"
          onPrev={onPrev}
          onStar={onStar}
          onSkip={onSkip}
          onHome={onHome}
          disablePrev={disablePrev}
        />

        {/* 单词 + 爱心 */}
        <div
          style={{
            display: "flex",
            justifyContent: "center",
            alignItems: "center",
            gap: "0.7rem",
            flexWrap: "wrap",
          }}
        >
          <div style={heroWordStyle(0)} onClick={() => speakFrench(word.word)}>
            {word.word}
          </div>
          <HeartView count={heartCount} />
        </div>

        {/* 音标 */}
        <div
          onClick={() => speakFrench(word.word)}
          style={{
            textAlign: "center",
            color: COLORS.subtext,
            cursor: "pointer",
            marginTop: "0.25rem",
          }}
        >
          {word.phonetic} 🔊
        </div>

        {/* 词性 */}
        <div
          style={{
            textAlign: "center",
            marginTop: "0.85rem",
            color: COLORS.text,
            fontWeight: 600,
          }}
        >
          {word.type} · {word.translation}
        </div>

        {/* 图片 */}
        <div style={{ marginTop: "1rem", borderRadius: "16px", overflow: "hidden" }}>
          <img
            src={imageUrl || "https://picsum.photos/800/600"}
            alt={word.word}
            style={{ width: "100%", height: "180px", objectFit: "cover", display: "block" }}
            onError={(e) => {
              e.target.src = "https://picsum.photos/800/600";
            }}
          />
        </div>

        {/* meanings 列表 */}
        <div style={{ marginTop: "1rem" }}>
          {meanings.map((meaning, idx) => (
            <div
              key={idx}
              style={{
                padding: "0.85rem 0",
                borderBottom: "1px dashed #D8DADF",
                cursor: "pointer",
              }}
              onClick={() =>
                onSetMeaningExampleIndex(meaningExampleIndex === idx ? null : idx)
              }
            >
              <div style={{ fontWeight: 600, color: COLORS.text }}>{meaning}</div>
              <div
                style={{
                  color: COLORS.subtext,
                  fontSize: "0.88rem",
                  marginTop: "0.3rem",
                }}
              >
                点击查看对应例句与翻译
              </div>
              {meaningExampleIndex === idx && (
                <div
                  style={{
                    marginTop: "0.6rem",
                    color: COLORS.subtext,
                    lineHeight: 1.8,
                  }}
                >
                  <div>
                    <strong style={{ color: COLORS.text }}>{word.example}</strong>
                  </div>
                  <div>{word.exampleTranslation}</div>
                </div>
              )}
            </div>
          ))}
        </div>

        {/* 标签页 */}
        <div
          style={{
            background: COLORS.soft,
            borderRadius: "18px",
            padding: "1rem",
            marginTop: "1.2rem",
          }}
        >
          <div
            style={{
              display: "flex",
              gap: "0.5rem",
              flexWrap: "wrap",
              marginBottom: "1rem",
            }}
          >
            <button
              onClick={() => onSetDetailTab("usage")}
              style={detailTagStyle(detailTab === "usage", COLORS.green)}
            >
              用法
            </button>
            <button
              onClick={() => onSetDetailTab("derivative")}
              style={detailTagStyle(detailTab === "derivative", COLORS.pink)}
            >
              派生词
            </button>
            <button
              onClick={() => onSetDetailTab("syn")}
              style={detailTagStyle(detailTab === "syn", COLORS.orange)}
            >
              同/反义词
            </button>
            <button
              onClick={() => onSetDetailTab("note")}
              style={detailTagStyle(detailTab === "note", COLORS.lightBlue)}
            >
              笔记
            </button>
          </div>

          {detailTab === "usage" && (
            <div style={detailPanelStyle()}>
              {word.usages?.length ? (
                word.usages.map((u, i) => (
                  <div key={i} style={{ marginBottom: "1rem" }}>
                    <div style={{ fontWeight: 700, color: COLORS.text }}>{u.title}</div>
                    <div style={{ color: COLORS.subtext, marginTop: "0.35rem" }}>
                      {u.meaning}
                    </div>
                    <div style={{ marginTop: "0.45rem", lineHeight: 1.7 }}>
                      <strong>{u.example}</strong>
                      <div style={{ color: COLORS.subtext }}>{u.translation}</div>
                    </div>
                  </div>
                ))
              ) : (
                <div style={{ color: COLORS.subtext }}>暂无用法数据</div>
              )}
            </div>
          )}

          {detailTab === "derivative" && (
            <div style={detailPanelStyle()}>
              {word.derivatives?.length ? (
                word.derivatives.map((d, i) => (
                  <div key={i} style={{ marginBottom: "1rem" }}>
                    <div style={{ fontWeight: 700, color: COLORS.text }}>
                      {d.word} · {d.type}
                    </div>
                    <div style={{ color: COLORS.subtext, marginTop: "0.35rem" }}>
                      {d.meaning}
                    </div>
                    <div style={{ marginTop: "0.35rem" }}>最常用法：{d.usage}</div>
                    <div style={{ marginTop: "0.35rem", color: COLORS.subtext }}>
                      {d.example}
                    </div>
                  </div>
                ))
              ) : (
                <div style={{ color: COLORS.subtext }}>暂无派生词数据</div>
              )}
            </div>
          )}

          {detailTab === "syn" && (
            <div style={detailPanelStyle()}>
              {word.synonymsAntonyms?.length ? (
                word.synonymsAntonyms.map((s, i) => (
                  <div key={i} style={{ marginBottom: "1rem" }}>
                    <div style={{ fontWeight: 700, color: COLORS.text }}>
                      [{s.relation}] {s.word} · {s.type}
                    </div>
                    <div style={{ color: COLORS.subtext, marginTop: "0.35rem" }}>
                      {s.meaning}
                    </div>
                    <div style={{ marginTop: "0.35rem", color: COLORS.subtext }}>
                      {s.example}
                    </div>
                  </div>
                ))
              ) : (
                <div style={{ color: COLORS.subtext }}>暂无同反义词数据</div>
              )}
            </div>
          )}

          {detailTab === "note" && (
            <div style={detailPanelStyle()}>
              <textarea
                value={tempNote}
                onChange={(e) => onSetTempNote(e.target.value)}
                placeholder="写下你对这个单词的任何想法..."
                style={{
                  width: "100%",
                  minHeight: "140px",
                  borderRadius: "14px",
                  border: `1px solid ${COLORS.line}`,
                  padding: "1rem",
                  resize: "vertical",
                  fontSize: "0.95rem",
                  boxSizing: "border-box",
                }}
              />
              <button
                onClick={onSaveNote}
                style={{
                  ...miniBtnStyle(),
                  width: "100%",
                  marginTop: "0.8rem",
                  borderRadius: "14px",
                  padding: "0.9rem 1rem",
                }}
              >
                保存笔记
              </button>
            </div>
          )}
        </div>

        {/* ✅ 底部按钮（卡片式、圆角、颜色边框） */}
        <div style={{ display: "flex", gap: "1rem", marginTop: "1.5rem" }}>
          <button
            onClick={onNext}
            style={{
              flex: 1,
              padding: "0.95rem 0",
              borderRadius: "14px",
              border: `2px solid ${COLORS.green}`,
              background: "#f0fff4",
              color: COLORS.text,
              fontWeight: 600,
              cursor: "pointer",
            }}
          >
            下一个
          </button>
          <button
            onClick={onMarkWrong}
            style={{
              flex: 1,
              padding: "0.95rem 0",
              borderRadius: "14px",
              border: `2px solid ${COLORS.red}`,
              background: "#fff5f5",
              color: COLORS.text,
              fontWeight: 600,
              cursor: "pointer",
            }}
          >
            记错了
          </button>
        </div>
      </div>
    </div>
  );
}