import React, { useState, useMemo, useEffect } from "react";
import COLORS from "../../constants/colors";
import { DEFAULT_WORDS } from "../../data/words"; // 导入单词库
import { getToday, addDays, diffDays } from "../../utils/date"; // 复用统一的日期工具函数
import {
  contentSectionStyle,
  listCardStyle,
  mainCardStyle,
  pageStyle,
  sectionTitleStyle,
  smallTopBtnStyle,
} from "../../styles/commonStyles";

// 2. 读取单词学习进度（从localStorage）
const getWordProgress = (wordId) => {
  const progress = JSON.parse(localStorage.getItem("wordProgress")) || {};
  return progress[wordId] || {
    learnedAt: "",
    reviewDue: "",
    reviewCount: 0,
    memoryStage: 0, // 0=未学习 1=1天后 2=3天后 3=7天后 4=30天后 5=已掌握
  };
};

// 3. 生成艾宾浩斯曲线统计数据（适配1/3/7/30天复习周期）
const generateCurveStats = (allWords) => {
  const today = getToday();
  // 固定分类标签：今日到期、一天后到期、三天后到期、七天后到期、三十天后到期
  const stats = [
    { label: "今日到期", count: 0 },
    { label: "一天后到期", count: 0 },
    { label: "三天后到期", count: 0 },
    { label: "七天后到期", count: 0 },
    { label: "三十天后到期", count: 0 },
  ];

  allWords.forEach((word) => {
    const p = getWordProgress(word.id);
    if (!p.learnedAt) return; // 未学习的单词跳过

    // 核心逻辑：根据复习次数计算到期日（确保时间计算统一）
    let reviewDue = "";
    if (p.reviewCount === 0) {
      // 首次学习：1天后到期
      reviewDue = p.reviewDue || addDays(p.learnedAt, 1);
    } else if (p.reviewCount === 1) {
      // 第一次复习后：3天后到期
      reviewDue = p.reviewDue || addDays(p.learnedAt, 3);
    } else if (p.reviewCount === 2) {
      // 第二次复习后：7天后到期
      reviewDue = p.reviewDue || addDays(p.learnedAt, 7);
    } else if (p.reviewCount === 3) {
      // 第三次复习后：30天后到期
      reviewDue = p.reviewDue || addDays(p.learnedAt, 30);
    } else {
      // 超过3次复习：默认30天后
      reviewDue = p.reviewDue || addDays(p.learnedAt, 30);
    }

    const dayDiff = diffDays(reviewDue, today);

    // 按时间差分类（动态更新）
    if (dayDiff <= 0) {
      stats[0].count += 1; // 今日到期（含逾期）
    } else if (dayDiff === 1) {
      stats[1].count += 1; // 一天后到期
    } else if (dayDiff >= 2 && dayDiff <= 3) {
      stats[2].count += 1; // 三天后到期
    } else if (dayDiff >= 4 && dayDiff <= 7) {
      stats[3].count += 1; // 七天后到期
    } else {
      stats[4].count += 1; // 三十天后到期
    }
  });

  return stats;
};

export default function StatisticsPage({
  state,
  onGoHome,
  starredWords = [],
  showTempMessage = () => {},
  openWordDetail = () => {},
  speakFrench = () => {},
  allWords = DEFAULT_WORDS, // 默认使用完整单词库
}) {
  // 新增：监听localStorage中wordProgress变化，实时刷新统计
  const [wordProgressUpdated, setWordProgressUpdated] = useState(Date.now());
  useEffect(() => {
    const handleStorageChange = (e) => {
      if (e.key === "wordProgress") {
        setWordProgressUpdated(Date.now()); // 触发重新计算
        showTempMessage("学习进度已更新", 1000);
      }
    };
    window.addEventListener("storage", handleStorageChange);
    return () => window.removeEventListener("storage", handleStorageChange);
  }, []);

  // 4. 计算艾宾浩斯统计数据（缓存优化：加入wordProgressUpdated依赖）
  const statsForCurve = useMemo(() => 
    generateCurveStats(allWords), 
    [allWords, wordProgressUpdated] // 进度变化时重新计算
  );

  // 容错：避免Math.max空数组报错
  const maxCurve = statsForCurve.length > 0 
    ? Math.max(...statsForCurve.map((x) => x.count), 1) 
    : 1;

  // 5. 读取学习/复习/拼写历史（最近7天）
  const learnedHistory = useMemo(() => {
    const stored = JSON.parse(localStorage.getItem("learnedHistory")) || [];
    return Array.isArray(stored) ? stored.slice(-7) : [];
  }, [wordProgressUpdated]); // 进度变化时刷新历史
  
  const reviewHistory = Array.isArray(state.user?.reviewHistory) 
    ? state.user.reviewHistory.slice(-7) 
    : [];
    
  const spellingHistory = Array.isArray(state.user?.spellingHistory) 
    ? state.user.spellingHistory.slice(-7) 
    : [];

  // 提取所有学习日期并排序
  const allDates = Array.from(
    new Set([
      ...learnedHistory.map((x) => x.date),
      ...reviewHistory.map((x) => x.date),
      ...spellingHistory.map((x) => x.date),
    ])
  ).sort((a, b) => new Date(a) - new Date(b));

  // 计算累计数据
  const totalLearn = learnedHistory.reduce((sum, x) => sum + (x.count || 0), 0);
  const totalReview = reviewHistory.reduce((sum, x) => sum + (x.count || 0), 0);
  const totalSpelling = spellingHistory.reduce((sum, x) => sum + (x.count || 0), 0);

  // 6. 状态管理：控制遗忘曲线单词列表显示
  const [activeCurveLabel, setActiveCurveLabel] = useState(null);
  const [curveWords, setCurveWords] = useState([]);

  // 7. 点击统计项的交互逻辑
  const handleStatClick = (type, value, label = "") => {
    const messages = {
      learn: `累计学习 ${value} 个单词`,
      review: `累计复习 ${value} 个单词`,
      spelling: `累计拼写 ${value} 个单词`,
      checkin: `连续签到 ${value} 天`,
      energy: `当前能量值 ${value}`,
      starred: `星标单词 ${value} 个`,
      curve: `该分类下有 ${value} 个单词待复习`
    };
    showTempMessage(messages[type] || "查看详情", 1500);

    // 点击遗忘曲线项，加载对应单词列表
    if (type === "curve") {
      if (value > 0) {
        calculateCurveWords(label);
        setActiveCurveLabel(label);
      } else {
        showTempMessage(`该分类下暂无待复习单词`, 1500);
        setActiveCurveLabel(null);
        setCurveWords([]);
      }
    }
  };

  // 8. 核心：计算对应分类的艾宾浩斯单词列表（适配1/3/7/30天复习周期）
  const calculateCurveWords = (label) => {
    const today = getToday();
    const words = [];

    allWords.forEach((word) => {
      const p = getWordProgress(word.id);
      if (!p.learnedAt) return;

      // 同步generateCurveStats的到期日计算逻辑
      let reviewDue = "";
      if (p.reviewCount === 0) {
        reviewDue = p.reviewDue || addDays(p.learnedAt, 1);
      } else if (p.reviewCount === 1) {
        reviewDue = p.reviewDue || addDays(p.learnedAt, 3);
      } else if (p.reviewCount === 2) {
        reviewDue = p.reviewDue || addDays(p.learnedAt, 7);
      } else if (p.reviewCount === 3) {
        reviewDue = p.reviewDue || addDays(p.learnedAt, 30);
      } else {
        reviewDue = p.reviewDue || addDays(p.learnedAt, 30);
      }

      const dayDiff = diffDays(reviewDue, today);
      let wordLabel = "";

      // 与分类逻辑完全一致（动态更新）
      if (dayDiff <= 0) wordLabel = "今日到期";
      else if (dayDiff === 1) wordLabel = "一天后到期";
      else if (dayDiff >= 2 && dayDiff <= 3) wordLabel = "三天后到期";
      else if (dayDiff >= 4 && dayDiff <= 7) wordLabel = "七天后到期";
      else wordLabel = "三十天后到期";

      if (wordLabel === label) {
        words.push({
          ...word,
          ...p,
          dueDate: reviewDue,
          dueInDays: dayDiff < 0 ? `已逾期${Math.abs(dayDiff)}天` : `${dayDiff}天`,
        });
      }
    });

    // 按到期时间排序（逾期在前，近的在前）
    words.sort((a, b) => {
      const diffA = diffDays(a.dueDate, today);
      const diffB = diffDays(b.dueDate, today);
      return diffA - diffB;
    });

    setCurveWords(words);
  };

  // 9. 关闭遗忘曲线单词列表
  const closeCurveWords = () => {
    setActiveCurveLabel(null);
    setCurveWords([]);
  };

  // 10. 播放单词发音（阻止冒泡）
  const handleSpeakWord = (word, e) => {
    e.stopPropagation();
    speakFrench(word);
    showTempMessage(`🔊 播放发音: ${word}`, 1000);
  };

  return (
    <div style={pageStyle()}>
      <div style={mainCardStyle()}>
        {/* 头部：标题 + 返回主页 */}
        <div
          style={{
            display: "flex",
            justifyContent: "space-between",
            alignItems: "center",
            marginBottom: "1rem",
          }}
        >
          <div
            style={{
              fontSize: "1.35rem",
              fontWeight: 800,
              color: COLORS.text,
            }}
          >
            学习情况
          </div>

          <button 
            onClick={() => {
              showTempMessage("返回主页", 1000);
              onGoHome();
            }} 
            style={smallTopBtnStyle("#E9EEF5")}
          >
            ⌂
          </button>
        </div>

        {/* 1. 艾宾浩斯遗忘曲线统计 */}
        <section style={contentSectionStyle()}>
          <div style={sectionTitleStyle()}>1. 艾宾浩斯遗忘曲线 </div>
          <div style={{ color: COLORS.subtext, marginBottom: "1rem" }}>
            学习后自动生成复习计划，随时间推移更新分类（点击查看具体单词）
          </div>

          <div style={{ display: "grid", gap: "0.9rem" }}>
            {statsForCurve.map((item) => (
              <div 
                key={item.label}
                style={{ 
                  cursor: "pointer",
                  backgroundColor: activeCurveLabel === item.label ? "#f0f7ff" : "transparent",
                  padding: "0.5rem",
                  borderRadius: "8px",
                  transition: "background-color 0.2s ease"
                }}
                onClick={() => handleStatClick("curve", item.count, item.label)}
                onMouseEnter={(e) => {
                  if (activeCurveLabel !== item.label) {
                    e.currentTarget.style.backgroundColor = "#f8f9fa";
                  }
                }}
                onMouseLeave={(e) => {
                  if (activeCurveLabel !== item.label) {
                    e.currentTarget.style.backgroundColor = "transparent";
                  }
                }}
              >
                <div
                  style={{
                    display: "flex",
                    justifyContent: "space-between",
                    marginBottom: "0.3rem",
                  }}
                >
                  <span style={{ color: COLORS.text, fontWeight: item.count > 0 ? 700 : 400 }}>
                    {item.label}
                  </span>
                  <span style={{ 
                    color: item.count > 0 ? COLORS.blue : COLORS.subtext,
                    fontWeight: 700
                  }}>
                    {item.count}
                  </span>
                </div>

                <div
                  style={{
                    height: "10px",
                    background: "#EEF1F4",
                    borderRadius: "999px",
                    overflow: "hidden",
                    transition: "all 0.2s ease",
                  }}
                  onMouseEnter={(e) => {
                    e.currentTarget.style.background = "#E5E9F0";
                  }}
                  onMouseLeave={(e) => {
                    e.currentTarget.style.background = "#EEF1F4";
                  }}
                >
                  <div
                    style={{
                      width: `${(item.count / maxCurve) * 100}%`,
                      height: "100%",
                      background: `linear-gradient(90deg, ${COLORS.blue}, ${COLORS.gold})`,
                      transition: "width 0.3s ease",
                    }}
                  />
                </div>
              </div>
            ))}
          </div>

          {/* 遗忘曲线对应的单词列表 */}
          {activeCurveLabel && curveWords.length > 0 && (
            <div style={{ 
              marginTop: "1rem",
              padding: "1rem",
              background: "#f8f9fa",
              borderRadius: "12px",
              maxHeight: "300px",
              overflowY: "auto",
              boxShadow: "0 1px 3px rgba(0,0,0,0.05)"
            }}>
              <div style={{ 
                display: "flex", 
                justifyContent: "space-between", 
                alignItems: "center",
                marginBottom: "0.8rem",
                borderBottom: `1px solid ${COLORS.line}`,
                paddingBottom: "0.5rem"
              }}>
                <h4 style={{ 
                  margin: 0, 
                  color: COLORS.text,
                  fontSize: "1rem"
                }}>
                  {activeCurveLabel} 待复习单词 ({curveWords.length})
                </h4>
                <button
                  style={{
                    background: "transparent",
                    border: "none",
                    cursor: "pointer",
                    color: COLORS.subtext,
                    fontSize: "1.2rem",
                    padding: "0.2rem",
                    lineHeight: 1,
                  }}
                  onClick={closeCurveWords}
                  aria-label="关闭单词列表"
                >
                  ✕
                </button>
              </div>

              <div style={{ display: "grid", gap: "0.8rem" }}>
                {curveWords.map((word) => (
                  <div 
                    key={word.id}
                    style={{
                      ...listCardStyle(),
                      cursor: "pointer",
                      transition: "all 0.2s ease",
                      display: "flex",
                      justifyContent: "space-between",
                      alignItems: "center",
                      background: "#fff",
                      padding: "0.8rem"
                    }}
                    onClick={() => {
                      showTempMessage(`查看单词详情：${word.word}`, 1000);
                      openWordDetail(word.id, { type: "statistics", stage: "curve" });
                    }}
                    onMouseEnter={(e) => {
                      e.currentTarget.style.boxShadow = "0 2px 12px rgba(0,0,0,0.1)";
                      e.currentTarget.style.transform = "translateY(-2px)";
                    }}
                    onMouseLeave={(e) => {
                      e.currentTarget.style.boxShadow = "none";
                      e.currentTarget.style.transform = "translateY(0)";
                    }}
                  >
                    <div style={{ flex: 1 }}>
                      <div style={{ 
                        fontWeight: 700, 
                        color: COLORS.text,
                        fontSize: "1.1rem"
                      }}>
                        {word.word}
                      </div>
                      <div style={{ 
                        color: COLORS.subtext, 
                        marginTop: "0.2rem",
                        fontSize: "0.9rem",
                        display: "flex",
                        justifyContent: "space-between"
                      }}>
                        <span>{word.translation}</span>
                        <span style={{ 
                          color: word.dueInDays.includes("已逾期") ? "#e53e3e" : COLORS.gold,
                          fontSize: "0.8rem",
                          fontWeight: 600
                        }}>
                          {word.dueInDays}
                        </span>
                      </div>
                      <div style={{ 
                        color: COLORS.subtext, 
                        fontSize: "0.8rem",
                        marginTop: "0.1rem",
                        display: "flex",
                        justifyContent: "space-between",
                        flexWrap: "wrap"
                      }}>
                        <span>学习于：{word.learnedAt || "未知时间"}</span>
                        <span>已复习：{word.reviewCount || 0} 次</span>
                      </div>
                      {word.phonetic && (
                        <div style={{ 
                          color: COLORS.blue, 
                          fontSize: "0.8rem",
                          marginTop: "0.1rem"
                        }}>
                          {word.phonetic}
                        </div>
                      )}
                    </div>
                    
                    <button
                      style={{
                        background: "transparent",
                        border: "none",
                        cursor: "pointer",
                        color: COLORS.gold,
                        fontSize: "1.2rem",
                        padding: "0.5rem",
                        borderRadius: "50%",
                        transition: "background 0.2s ease"
                      }}
                      onClick={(e) => handleSpeakWord(word.word, e)}
                      onMouseEnter={(e) => {
                        e.currentTarget.style.background = "#f0f4ff";
                      }}
                      onMouseLeave={(e) => {
                        e.currentTarget.style.background = "transparent";
                      }}
                      aria-label={`播放${word.word}的发音`}
                    >
                      🔊
                    </button>
                  </div>
                ))}
              </div>
            </div>
          )}
        </section>

        {/* 2. 每日学习情况 */}
        <section style={contentSectionStyle()}>
          <div style={sectionTitleStyle()}>2. 每日学习情况</div>
          <div 
            style={{ marginBottom: "0.8rem", color: COLORS.subtext, cursor: "pointer" }}
            onClick={() => {
              handleStatClick("learn", totalLearn);
              handleStatClick("review", totalReview);
              handleStatClick("spelling", totalSpelling);
            }}
          >
            累计学习：{totalLearn} · 累计复习：{totalReview} · 累计拼写：{totalSpelling}
          </div>

          <div style={{ display: "grid", gap: "0.8rem" }}>
            {allDates.length === 0 ? (
              <div style={{ 
                color: COLORS.subtext, 
                textAlign: "center",
                padding: "1.5rem",
                background: "#f8f9fa",
                borderRadius: "8px"
              }}>
                📝 暂无学习数据<br />
                开始学习后这里会显示每日进度
              </div>
            ) : (
              allDates.map((date) => {
                const learnCount = learnedHistory.find((x) => x.date === date)?.count || 0;
                const reviewCount = reviewHistory.find((x) => x.date === date)?.count || 0;
                const spellingCount = spellingHistory.find((x) => x.date === date)?.count || 0;
                const total = learnCount + reviewCount + spellingCount;

                return (
                  <div 
                    key={date} 
                    style={{
                      ...listCardStyle(),
                      cursor: "pointer",
                      transition: "box-shadow 0.2s ease",
                      display: "flex",
                      justifyContent: "space-between",
                      alignItems: "center",
                      padding: "0.8rem"
                    }}
                    onClick={() => {
                      showTempMessage(`${date}：学习${learnCount} · 复习${reviewCount} · 拼写${spellingCount}`, 2000);
                    }}
                    onMouseEnter={(e) => {
                      e.currentTarget.style.boxShadow = "0 2px 8px rgba(0,0,0,0.08)";
                    }}
                    onMouseLeave={(e) => {
                      e.currentTarget.style.boxShadow = "none";
                    }}
                  >
                    <div>
                      <div style={{ fontWeight: 700, color: COLORS.text }}>{date}</div>
                      <div
                        style={{
                          color: COLORS.subtext,
                          marginTop: "0.2rem",
                          lineHeight: 1.6,
                          fontSize: "0.9rem"
                        }}
                      >
                        学习：{learnCount} · 复习：{reviewCount} · 拼写：{spellingCount}
                      </div>
                    </div>

                    <div style={{ 
                      color: COLORS.blue, 
                      fontWeight: 700, 
                      fontSize: "1.1rem",
                      minWidth: "2rem",
                      textAlign: "right"
                    }}>
                      {total}
                    </div>
                  </div>
                );
              })
            )}
          </div>
        </section>

        {/* 3. 当前学习状态概览 */}
        <section style={contentSectionStyle()}>
          <div style={sectionTitleStyle()}>3. 当前学习状态概览</div>

          <div style={{ display: "grid", gap: "0.8rem" }}>
            <div 
              style={{
                ...listCardStyle(),
                cursor: "pointer",
                transition: "box-shadow 0.2s ease",
                padding: "0.8rem"
              }}
              onClick={() => handleStatClick("checkin", state.user?.streak || 0)}
              onMouseEnter={(e) => {
                e.currentTarget.style.boxShadow = "0 2px 8px rgba(0,0,0,0.08)";
              }}
              onMouseLeave={(e) => {
                e.currentTarget.style.boxShadow = "none";
              }}
            >
              <div>
                <div style={{ fontWeight: 700, color: COLORS.text }}>累计签到</div>
                <div style={{ color: COLORS.subtext, marginTop: "0.25rem", fontSize: "0.9rem" }}>
                  当前连续签到天数
                </div>
              </div>
              <div style={{ color: COLORS.blue, fontWeight: 800, fontSize: "1.1rem" }}>
                {state.user?.streak || 0}
              </div>
            </div>

            <div 
              style={{
                ...listCardStyle(),
                cursor: "pointer",
                transition: "box-shadow 0.2s ease",
                padding: "0.8rem"
              }}
              onClick={() => handleStatClick("energy", state.user?.energy || 0)}
              onMouseEnter={(e) => {
                e.currentTarget.style.boxShadow = "0 2px 8px rgba(0,0,0,0.08)";
              }}
              onMouseLeave={(e) => {
                e.currentTarget.style.boxShadow = "none";
              }}
            >
              <div>
                <div style={{ fontWeight: 700, color: COLORS.text }}>当前能量值</div>
                <div style={{ color: COLORS.subtext, marginTop: "0.25rem", fontSize: "0.9rem" }}>
                  用于解锁巴黎地图场景
                </div>
              </div>
              <div style={{ color: COLORS.blue, fontWeight: 800, fontSize: "1.1rem" }}>
                ★{state.user?.energy || 0}
              </div>
            </div>

            <div 
              style={{
                ...listCardStyle(),
                cursor: "pointer",
                transition: "box-shadow 0.2s ease",
                padding: "0.8rem"
              }}
              onClick={() => handleStatClick("starred", starredWords.length || 0)}
              onMouseEnter={(e) => {
                e.currentTarget.style.boxShadow = "0 2px 8px rgba(0,0,0,0.08)";
              }}
              onMouseLeave={(e) => {
                e.currentTarget.style.boxShadow = "none";
              }}
            >
              <div>
                <div style={{ fontWeight: 700, color: COLORS.text }}>星标单词数</div>
                <div style={{ color: COLORS.subtext, marginTop: "0.25rem", fontSize: "0.9rem" }}>
                  已加入单词本的重点词汇
                </div>
              </div>
              <div style={{ color: COLORS.gold, fontWeight: 800, fontSize: "1.1rem" }}>
                {starredWords.length || 0}
              </div>
            </div>
          </div>
        </section>

        {/* 4. 我的星标单词 */}
        <section style={contentSectionStyle()}>
          <div style={sectionTitleStyle()}>4. 我的星标单词</div>
          <div style={{ color: COLORS.subtext, marginBottom: "1rem", fontSize: "0.9rem" }}>
            点击单词查看详情，点击喇叭图标播放发音
          </div>

          {starredWords.length === 0 ? (
            <div style={{ 
              color: COLORS.subtext, 
              textAlign: "center", 
              padding: "2rem 0",
              borderRadius: "12px",
              background: "#f8f9fa"
            }}>
              📖 暂无星标单词<br />
              学习过程中点击⭐可收藏重点单词
            </div>
          ) : (
            <div style={{ 
              display: "grid", 
              gap: "0.8rem",
              maxHeight: "400px",
              overflowY: "auto",
              paddingRight: "0.5rem"
            }}>
              {starredWords.map((word) => (
                <div 
                  key={word.id}
                  style={{
                    ...listCardStyle(),
                    cursor: "pointer",
                    transition: "all 0.2s ease",
                    display: "flex",
                    justifyContent: "space-between",
                    alignItems: "center",
                    padding: "0.8rem"
                  }}
                  onClick={() => {
                    showTempMessage(`查看单词详情：${word.word}`, 1000);
                    openWordDetail(word.id, { type: "statistics", stage: "starred" });
                  }}
                  onMouseEnter={(e) => {
                    e.currentTarget.style.boxShadow = "0 2px 12px rgba(0,0,0,0.1)";
                    e.currentTarget.style.transform = "translateY(-2px)";
                  }}
                  onMouseLeave={(e) => {
                    e.currentTarget.style.boxShadow = "none";
                    e.currentTarget.style.transform = "translateY(0)";
                  }}
                >
                  <div style={{ flex: 1 }}>
                    <div style={{ 
                      fontWeight: 700, 
                      color: COLORS.text,
                      fontSize: "1.1rem"
                    }}>
                      {word.word}
                    </div>
                    <div style={{ 
                      color: COLORS.subtext, 
                      marginTop: "0.2rem",
                      fontSize: "0.9rem"
                    }}>
                      {word.translation}
                    </div>
                    {word.phonetic && (
                      <div style={{ 
                        color: COLORS.blue, 
                        fontSize: "0.8rem",
                        marginTop: "0.1rem"
                      }}>
                        {word.phonetic}
                      </div>
                    )}
                  </div>
                  
                  <button
                    style={{
                      background: "transparent",
                      border: "none",
                      cursor: "pointer",
                      color: COLORS.gold,
                      fontSize: "1.2rem",
                      padding: "0.5rem",
                      borderRadius: "50%",
                      transition: "background 0.2s ease"
                    }}
                    onClick={(e) => handleSpeakWord(word.word, e)}
                    onMouseEnter={(e) => {
                      e.currentTarget.style.background = "#f0f4ff";
                    }}
                    onMouseLeave={(e) => {
                      e.currentTarget.style.background = "transparent";
                    }}
                    aria-label={`播放${word.word}的发音`}
                  >
                    🔊
                  </button>
                </div>
              ))}
            </div>
          )}
        </section>
      </div>
    </div>
  );
}