import React from "react";
import COLORS from "../../constants/colors";
// 注意：如果 primaryBtnStyle 定义了冲突样式，我们直接在组件内定义基础样式
// import { primaryBtnStyle } from "../../styles/commonStyles";

export default function CheckInCard({
  streak,
  showCheckinText,
  onCheckIn,
}) {
  // 直接定义签到按钮的基础样式（替代外部引入的 primaryBtnStyle）
  // 确保不与 global.css 中的 hover 效果冲突
  const checkinButtonBaseStyle = {
    background: COLORS.blue || "#1976d2", // 匹配 global.css 中的 primary-btn 背景色
    color: COLORS.white,
    border: "none",
    borderRadius: "12px",
    padding: "0.8rem 1.2rem",
    fontWeight: 600,
    fontSize: "1rem",
    cursor: "pointer",
    // 保留基础过渡属性（与 global.css 保持一致）
    transition: "transform 0.2s ease, box-shadow 0.2s ease, background 0.2s ease",
  };

  return (
    <div
      style={{
        background: COLORS.white,
        borderRadius: "18px",
        padding: "1rem",
        marginBottom: "1rem",
        border: `1px solid ${COLORS.line || "#e0e0e0"}`,
      }}
    >
      <div
        style={{
          display: "flex",
          justifyContent: "space-between",
          alignItems: "center",
          gap: "1rem",
        }}
      >
        <div>
          <div style={{ fontWeight: 700, color: COLORS.text || "#333" }}>签到</div>
          <div
            style={{
              color: COLORS.subtext || "#666",
              fontSize: "0.92rem",
              marginTop: "0.25rem",
            }}
          >
            点击记录你今天的法语脚步
          </div>
        </div>

        {/* 关键修改：
            1. 移除内联样式与 CSS 类的冲突
            2. 确保 className 正确应用
            3. 基础样式通过 style 传递，hover 效果由 global.css 接管
        */}
        <button 
          onClick={onCheckIn} 
          style={checkinButtonBaseStyle}
          className="checkin-btn hover-scale-btn" // 核心：应用 global.css 中的悬浮类
          // 强制确保按钮不被其他样式覆盖（可选）
          type="button"
        >
          签到
        </button>
      </div>

      {showCheckinText && (
        <div
          style={{
            marginTop: "0.8rem",
            color: COLORS.blue || "#1976d2",
            fontSize: "0.92rem",
          }}
        >
          恭喜已累计签到 {streak} 天
        </div>
      )}
    </div>
  );
}