import React from "react";
import COLORS from "../../constants/colors";
import {
  bigActionStyle,
  bigActionSubStyle,
} from "../../styles/commonStyles";

export default function HomeActionPanel({
  onStartLearn,
  onStartReview,
}) {
  return (
    <div style={{ marginTop: "1.3rem", marginBottom: "1.3rem" }}>
      <button
        onClick={onStartLearn}
        style={{
          ...bigActionStyle(COLORS.blue),
          marginBottom: "0.9rem",
        }}
      >
        Apprendre
        <div style={bigActionSubStyle()}>学习新词</div>
      </button>

      <button onClick={onStartReview} style={bigActionStyle(COLORS.green)}>
        Repasser
        <div style={bigActionSubStyle()}>复习旧词</div>
      </button>
    </div>
  );
}