import React, { useEffect } from "react";
import COLORS from "../../constants/colors";
import FlowTopBar from "../common/FlowTopBar";
import HeartView from "../common/HeartView";
import WordPreviewCard from "../common/WordPreviewCard";
import {
  centerSubStyle,
  heroWordStyle,
  mainCardStyle,
  pageStyle,
} from "../../styles/commonStyles";
import { speakFrench } from "../../utils/speech";

// 1. 新增日期工具函数（内置，无需额外文件）
const getToday = () => {
  const now = new Date();
  return `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, "0")}-${String(now.getDate()).padStart(2, "0")}`;
};

const addDays = (dateStr, days) => {
  const date = new Date(dateStr);
  date.setDate(date.getDate() + days);
  return `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, "0")}-${String(date.getDate()).padStart(2, "0")}`;
};

// 2. 新增进度存储函数（持久化到localStorage）
const updateWordProgress = (wordId, progress) => {
  const existing = JSON.parse(localStorage.getItem("wordProgress")) || {};
  existing[wordId] = { ...existing[wordId], ...progress };
  localStorage.setItem("wordProgress", JSON.stringify(existing));
};

export default function LearnPhaseOne({
  word,
  progressText,
  heartCount,
  options,
  triedOptions = [],
  onChooseOption,
  onOpenDetail,
  onPrev,
  onStar,
  onSkip,
  onHome,
  disablePrev = false,
}) {
  if (!word) return null;

  // 3. 判断是否选对答案（学习完成）
  const isLearned = triedOptions.includes(word.translation);

  // 4. 核心：选对后自动生成艾宾浩斯复习计划并存储
  useEffect(() => {
    if (isLearned && word?.id) {
      const learnedAt = getToday(); // 学习完成时间（今日）
      const reviewDue = addDays(learnedAt, 1); // 初始复习时间：1天后
      
      // 存储单词进度（包含艾宾浩斯核心字段）
      updateWordProgress(word.id, {
        learnedAt,
        reviewDue,
        reviewCount: 0, // 初始复习次数
        isLearned: true,
        word: word.word,
        translation: word.translation,
        phonetic: word.phonetic,
        type: word.type,
      });

      // 控制台验证（可选，上线可删）
      console.log(`单词【${word.word}】已存入艾宾浩斯曲线`, {
        wordId: word.id,
        learnedAt,
        reviewDue,
      });

      // 同步更新学习历史（保证StatisticsPage的「每天学习情况」也能显示）
      const learnedHistory = JSON.parse(localStorage.getItem("learnedHistory")) || [];
      const today = getToday();
      const todayRecord = learnedHistory.find(item => item.date === today);
      if (todayRecord) {
        todayRecord.count += 1;
      } else {
        learnedHistory.push({ date: today, count: 1 });
      }
      localStorage.setItem("learnedHistory", JSON.stringify(learnedHistory));
    }
  }, [isLearned, word]);

  return (
    <div style={pageStyle()}>
      <div style={mainCardStyle()}>
        {/* 顶部导航 */}
        <FlowTopBar
          title={`学习进度：${progressText}`}
          onPrev={onPrev}
          onStar={onStar}
          onSkip={onSkip}
          onHome={onHome}
          disablePrev={disablePrev}
        />

        {/* 爱心 */}
        <div style={{ display: "flex", justifyContent: "center", marginBottom: "0.3rem" }}>
          <HeartView count={heartCount} />
        </div>

        {/* 单词 + 发音 */}
        <div style={heroWordStyle()} onClick={() => speakFrench(word.word)}>
          {word.word}
        </div>
        <div
          style={{ ...centerSubStyle(), cursor: "pointer" }}
          onClick={() => speakFrench(word.word)}
        >
          {word.phonetic} 🔊
        </div>

        {/* 汉语选项 */}
        <div style={{ display: "grid", gap: "0.8rem", marginTop: "1.4rem" }}>
          {options.map((opt, i) => {
            const selected = triedOptions.includes(opt);
            const isCorrect = opt === word.translation;

            // 找到“该汉语对应的法语”
            const selectedFrench =
              word.allTranslations?.find((t) => t.cn === opt)?.fr;

            return (
              <div key={i}>
                <button
                  onClick={() => onChooseOption(opt)}
                  disabled={isLearned} // 选对后禁用，避免重复存储
                  style={{
                    width: "100%",
                    padding: "1rem",
                    borderRadius: "14px",
                    border: `1px solid ${
                      selected ? (isCorrect ? COLORS.green : COLORS.red) : COLORS.line
                    }`,
                    background: selected
                      ? isCorrect
                        ? COLORS.paleGreen
                        : COLORS.palePink
                      : "#FBFBFD",
                    color: COLORS.text,
                    textAlign: "left",
                    fontSize: "1rem",
                    cursor: isLearned ? "not-allowed" : "pointer",
                    opacity: isLearned ? 0.9 : 1,
                  }}
                >
                  <strong style={{ marginRight: "0.45rem", color: COLORS.blue }}>
                    {word.type}
                  </strong>
                  {opt}
                </button>

                {/* 选对：显示正确单词卡片 */}
                {selected && isCorrect && (
                  <WordPreviewCard word={word} onDetail={onOpenDetail} />
                )}

                {/* 选错：显示“你选的汉语 → 对应法语” */}
                {selected && !isCorrect && (
                  <WordPreviewCard
                    word={{
                      ...word,
                      word: selectedFrench || "（未找到对应法语）",
                      translation: opt,
                    }}
                    onDetail={onOpenDetail}
                  />
                )}
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
}