import React from "react";
import COLORS from "../../constants/colors";
import FlowTopBar from "../common/FlowTopBar";
import HeartView from "../common/HeartView";
import {
  btnBarStyle,
  centerSubStyle,
  exampleBoxStyle,
  heroWordStyle,
  hintBtnStyle,
  knowBtnStyle,
  mainCardStyle,
  pageStyle,
} from "../../styles/commonStyles";
import { speakFrench } from "../../utils/speech";

// 复用高亮单词函数
function highlightWord(example, word) {
  if (!example || !word) return example || "";
  const escaped = word.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
  return example.replace(new RegExp(escaped, "gi"), `<strong>${word}</strong>`);
}

// ✅ 新增：随机图片数组
const randomImages = [
  "https://images.unsplash.com/photo-1502602898657-3e91760cbb34?auto=format&fit=crop&w=800&q=80",
  "https://images.unsplash.com/photo-1492724441997-5dc865305da7?auto=format&fit=crop&w=800&q=80",
  "https://images.unsplash.com/photo-1517842645767-c639042777db?auto=format&fit=crop&w=800&q=80",
  "https://images.unsplash.com/photo-1551887196-72e32bfc7bf3?auto=format&fit=crop&w=800&q=80",
  "https://images.unsplash.com/photo-1529156069898-49953e39b3ac?auto=format&fit=crop&w=800&q=80",
];

// ✅ 新增：获取随机图片
const getRandomImage = () => {
  const randomIndex = Math.floor(Math.random() * randomImages.length);
  return randomImages[randomIndex];
};

// ✅ 修改后的图片展示函数（新增点击显示逻辑）
function getWordImageBlock(word, isShowImage, onShowImageClick) {
  // 优先显示单词自带图片（如果有）
  if (word?.image) {
    return (
      <img
        src={word.image}
        alt={word.word}
        style={{
          width: "100%",
          height: "180px",
          objectFit: "cover",
          borderRadius: "16px",
          marginBottom: "1rem",
          border: "1px solid #EAECEF",
          cursor: "pointer" // 增加点击光标提示
        }}
        onClick={onShowImageClick} // 绑定点击事件（不影响原有图片展示）
      />
    );
  }

  // 无单词图片时：未点击→显示空白框，点击→显示随机图片
  return (
    <div
      style={{
        width: "100%",
        height: "180px",
        borderRadius: "16px",
        marginBottom: "1rem",
        border: "1px solid #EAECEF",
        background: isShowImage 
          ? "none" // 显示图片时取消渐变背景
          : "linear-gradient(135deg, #EEF4FB 0%, #FFF7EE 100%)",
        cursor: "pointer", // 点击光标提示
        overflow: "hidden" // 防止图片溢出
      }}
      onClick={onShowImageClick} // 点击显示随机图片
    >
      {isShowImage && (
        <img
          src={getRandomImage()}
          alt="随机图片"
          style={{
            width: "100%",
            height: "100%",
            objectFit: "cover",
          }}
          onError={(e) => {
            // 图片加载失败兜底
            e.target.src = "https://images.unsplash.com/photo-1492724441997-5dc865305da7";
          }}
        />
      )}
    </div>
  );
}

export default function ReviewPhaseOne({
  word,
  progressText,
  heartCount,
  onKnown,
  onPrev,
  onStar,
  onSkip,
  onHome,
  disablePrev = false,
}) {
  // 保留提示阶段状态（和 LearnPhaseTwo 完全一致）
  const [hintStage, setHintStage] = React.useState(0);
  // 保留选中状态（原有 ReviewPhaseOne 的逻辑）
  const [selected, setSelected] = React.useState(null);
  // ✅ 新增：图片显示状态（初始不展示）
  const [isShowImage, setIsShowImage] = React.useState(false);

  // 处理提示点击逻辑（完全照搬 LearnPhaseTwo）
  const handleHintClick = () => {
    if (hintStage === 0) {
      setHintStage(1);
    } else if (hintStage === 1) {
      setHintStage(2);
    }
  };

  // 处理认识/不认识点击逻辑（兼容原有延迟回调）
  const handleKnowClick = (isKnown) => {
    if (selected) return;
    setSelected(isKnown);

    setTimeout(() => {
      if (typeof onKnown === 'function') {
        onKnown(isKnown);
      }
    }, 1000);
  };

  // ✅ 新增：点击显示图片的处理函数
  const handleShowImageClick = () => {
    if (!isShowImage) { // 仅第一次点击时显示
      setIsShowImage(true);
    }
  };

  // 空值保护
  if (!word) return null;

  return (
    <div style={pageStyle()}>
      <div style={mainCardStyle()}>
        {/* 顶部导航（完全照搬 FlowTopBar） */}
        <FlowTopBar
          title={`学习进度：${progressText}`}
          onPrev={onPrev}
          onStar={onStar}
          onSkip={onSkip}
          onHome={onHome}
          disablePrev={disablePrev}
        />

        {/* 爱心展示（完全照搬 HeartView） */}
        <div style={{ display: "flex", justifyContent: "center", margin: "0.5rem 0" }}>
          <HeartView count={heartCount} />
        </div>

        {/* 单词 + 发音（完全照搬，保留点击发音） */}
        <div
          style={{ textAlign: "center", cursor: "pointer", marginBottom: "0.5rem" }}
          onClick={() => speakFrench(word.word)}
        >
          <div style={heroWordStyle()}>{word.word}</div>
          <div style={{ ...centerSubStyle(), marginTop: "0.2rem", color: COLORS.subtext }}>
            {word.phonetic} 🔊
          </div>
        </div>

        {/* ✅ 修改：传入图片显示状态和点击事件 */}
        <div>{getWordImageBlock(word, isShowImage, handleShowImageClick)}</div>

        {/* 法语提示面板（完全照搬） */}
        <div
          style={{
            width: "100%",
            height: "60px",
            borderRadius: "12px",
            border: "1px solid #EAECEF",
            marginBottom: "0.8rem",
            backgroundColor: "#F9F9F9",
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            padding: "0 1rem",
          }}
        >
          {hintStage >= 1 && (
            <span style={{ color: COLORS.text, fontSize: "1rem", fontWeight: 500 }}>
              {word.frenchHint || `Définition: ${word.word}`}
            </span>
          )}
        </div>
        
        {/* 汉语提示面板（完全照搬） */}
        <div
          style={{
            width: "100%",
            height: "60px",
            borderRadius: "12px",
            border: "1px solid #EAECEF",
            marginBottom: "1rem",
            backgroundColor: "#F9F9F9",
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            padding: "0 1rem",
          }}
        >
          {hintStage >= 2 && (
            <span style={{ color: COLORS.blue, fontSize: "1rem", fontWeight: 600 }}>
              {word.translation || "暂无中文释义"}
            </span>
          )}
        </div>

        {/* 例句面板（完全照搬，保留高亮和翻译显示逻辑） */}
        <div style={exampleBoxStyle()}>
          <span
            dangerouslySetInnerHTML={{
              __html: highlightWord(word.example, word.word),
            }}
          />
          {hintStage >= 2 && (
            <div style={{ marginTop: "0.7rem", color: COLORS.subtext }}>
              {word.exampleTranslation}
            </div>
          )}
        </div>

        {/* 提示按钮（完全照搬，文案随阶段变化） */}
        <div style={{ textAlign: "center", margin: "1rem 0" }}>
          <button onClick={handleHintClick} style={hintBtnStyle()}>
            💡
            <div style={{ fontSize: "0.86rem", marginTop: "0.2rem" }}>
              {hintStage === 0 ? "提示一下" : hintStage === 1 ? "显示中文意思" : "已显示全部提示"}
            </div>
          </button>
        </div>

        {/* 操作按钮（保留原有延迟逻辑，样式完全照搬） */}
        <div style={{ display: "flex", gap: "1rem", marginBottom: "0.5rem" }}>
          <button 
            onClick={() => handleKnowClick(true)} 
            style={{
              ...knowBtnStyle(),
              opacity: selected === true ? 0.8 : 1,
              pointerEvents: selected ? 'none' : 'auto'
            }}
          >
            认识
            <div style={btnBarStyle(COLORS.green)} />
          </button>
          <button 
            onClick={() => handleKnowClick(false)} 
            style={{
              ...knowBtnStyle(),
              opacity: selected === false ? 0.8 : 1,
              pointerEvents: selected ? 'none' : 'auto'
            }}
          >
            不认识
            <div style={btnBarStyle(COLORS.red)} />
          </button>
        </div>
      </div>
    </div>
  );
}