import React from "react";
import COLORS from "../../constants/colors";
import FlowTopBar from "../common/FlowTopBar";
import MaskedInputPlaceholder from "../common/MaskedInputPlaceholder";
import {
  heroWordStyle,
  mainCardStyle,
  pageStyle,
  primaryBtnStyle,
  centerSubStyle,
} from "../../styles/commonStyles";
import { speakFrench } from "../../utils/speech";

export default function ReviewPhaseTwoInput({
  word,
  progressText,
  inputValue,
  checkResult,
  onChangeInput,
  onCheck,
  onPrev,
  onStar,
  onSkip,
  onHome,
  disablePrev = false,
}) {
  if (!word) return null;

  return (
    <div style={pageStyle()}>
      <div style={mainCardStyle()}>
        <FlowTopBar
          title={`复习进度：${progressText}`}
          onPrev={onPrev}
          onStar={onStar}
          onSkip={onSkip}
          onHome={onHome}
          disablePrev={disablePrev}
        />

        <div style={heroWordStyle()}>{word.word}</div>

        <div
          onClick={() => speakFrench(word.word)}
          style={{ ...centerSubStyle(), cursor: "pointer" }}
        >
          {word.phonetic} 🔊
        </div>

        <MaskedInputPlaceholder />

        <div
          style={{
            marginTop: "1.4rem",
            textAlign: "center",
            color: COLORS.text,
            fontWeight: 700,
            fontSize: "1.05rem",
          }}
        >
          请输入中文意思
        </div>

        <div style={{ display: "flex", justifyContent: "center", marginTop: "1rem" }}>
          <input
            value={inputValue}
            onChange={(e) => onChangeInput(e.target.value)}
            placeholder="请输入中文释义"
            style={{
              width: "100%",
              maxWidth: "420px",
              border: "none",
              outline: "none",
              borderBottom: `3px solid ${
                checkResult === "correct"
                  ? COLORS.green
                  : checkResult === "wrong"
                  ? COLORS.red
                  : "#C9CDD4"
              }`,
              padding: "0.8rem 0.4rem",
              fontSize: "1.15rem",
              textAlign: "center",
              background: "transparent",
              color: COLORS.text,
            }}
          />
        </div>

        {checkResult === "correct" && (
          <div
            style={{
              textAlign: "center",
              marginTop: "1rem",
              color: COLORS.green,
              fontWeight: 700,
            }}
          >
            回答正确，正在进入下一题
          </div>
        )}

        {checkResult === "wrong" && (
          <div
            style={{
              textAlign: "center",
              marginTop: "1rem",
              color: COLORS.red,
              fontWeight: 700,
            }}
          >
            回答错误，请重新输入
          </div>
        )}

        <button
          onClick={onCheck}
          style={{
            ...primaryBtnStyle(),
            width: "100%",
            marginTop: "1.6rem",
          }}
        >
          提交检查
        </button>
      </div>
    </div>
  );
}